class DecreasingDesirabilityObjective(BaseModel):
    """
    An objective returning a reward the negative, shifted scaled identity, but trimmed at the bounds:

        d = ((upper_bound - x) / (upper_bound - lower_bound))^t

    where:

        t = exp(log_shape_factor)

    Note, that with clipping the reward is always between zero and one.

    Attributes:
        clip (bool): Whether to clip the values below/above the lower/upper bound, by
            default True.
        log_shape_factor (float): Logarithm of the shape factor:
            Whether the interpolation between the lower bound and the upper is linear (=0),
            convex (>0) or concave (<0) , by default 0.0.
        w (float): relative weight, by default = 1.
        bounds (tuple[float]): lower and upper bound of the desirability. Below
            bounds[0] the desirability is =1 (if clip=True) or >1 (if clip=False). Above
            bounds[1] the desirability is =0  (if clip=True) or <0 (if clip=False).
            Defaults to (0, 1).
    """

    model_config = ConfigDict(
        extra='forbid',
        validate_by_name=True,
    )
    bounds: Annotated[
        Bounds13 | Bounds14, Field(title='Bounds', validate_default=True)
    ] = [0, 1]
    clip: Annotated[bool, Field(title='Clip')] = True
    log_shape_factor: Annotated[float, Field(title='Log Shape Factor')] = 0.0
    type: Annotated[
        Literal['DecreasingDesirabilityObjective'], Field(title='Type')
    ] = 'DecreasingDesirabilityObjective'
    w: Annotated[float, Field(gt=0.0, le=1.0, title='W')] = 1


class Type33(RootModel[Literal['DimensionalityScaledGammaPrior']]):
    root: Annotated[
        Literal['DimensionalityScaledGammaPrior'], Field(title='Type')
    ] = 'DimensionalityScaledGammaPrior'


class DimensionalityScaledGammaPrior(BaseModel):
    """
    Gamma prior whose concentration and rate are scaled by the dimensionality of
    the problem, so that the lengthscale mode can grow with the problem dimensionality.

    The effective gamma distribution used at mapping time (given the dimensionality
    ``d``) is::

        concentration_eff = concentration + concentration_scaling * sqrt(d)
        rate_eff          = rate * d ** rate_power

    The asymmetric scaling (additive on the concentration, power on the rate) makes it
    possible to express both the CHEN priors (concentration growing with sqrt(d), rate
    fixed) and the dimensionality-scaled threesix prior (concentration fixed, rate
    decaying with sqrt(d)) with a single, serializable prior. See the constants in
    ``bofire.data_models.priors.api`` (``CHEN_*``,
    ``DIMENSIONALITY_SCALED_THREESIX_LENGTHSCALE_PRIOR``).

    Attributes:
        concentration(PositiveFloat): base concentration of the gamma distribution.
        concentration_scaling(float): factor multiplying ``sqrt(d)`` that is added to
            the base concentration.
        rate(PositiveFloat): base rate of the gamma distribution.
        rate_power(float): exponent of ``d`` that the base rate is multiplied by.
    """

    model_config = ConfigDict(
        extra='forbid',
        validate_by_name=True,
    )
    concentration: Annotated[float, Field(gt=0.0, title='Concentration')] = 3.0
    concentration_scaling: Annotated[float, Field(title='Concentration Scaling')] = 0.0
    rate: Annotated[float, Field(gt=0.0, title='Rate')] = 6.0
    rate_power: Annotated[float, Field(title='Rate Power')] = 0.0
    type: Annotated[
        Literal['DimensionalityScaledGammaPrior'], Field(title='Type')
    ] = 'DimensionalityScaledGammaPrior'


