class SmoothedBoxPrior(BaseModel):
    """
    A smoothed approximation of a uniform prior.

    .. math::

    egin{equation*}
        B = {x: a_i <= x_i <= b_i}
        d(x, B) = min_{x' in B} |x - x'|
        pdf(x) \\sim exp(- d(x, B)**2 / sqrt(2 * sigma^2))
    \\end{equation*}

    Attributes:
        lower_bound: lower bound of the uniform prior
        upper_bound: upper bound of the uniform prior
        sigma: related to pdf(x)
    """

    model_config = ConfigDict(
        extra='forbid',
        validate_by_name=True,
    )
    lower_bound: Annotated[float, Field(title='Lower Bound')]
    sigma: Annotated[float, Field(gt=0.0, title='Sigma')] = 0.01
    type: Annotated[Literal['SmoothedBoxPrior'], Field(title='Type')] = (
        'SmoothedBoxPrior'
    )
    upper_bound: Annotated[float, Field(title='Upper Bound')]


