    frequency_check: Annotated[int, Field(gt=0, title='Frequency Check')] = 1
    frequency_hyperopt: Annotated[int, Field(ge=0, title='Frequency Hyperopt')] = 0
    include_infeasible_exps_in_acqf_calc: Annotated[
        bool, Field(title='Include Infeasible Exps In Acqf Calc')
    ] = False
    """Whether infeasible experiments should be included in the set of experiments used to compute the acquisition function."""
    min_experiments_before_outlier_check: Annotated[
        int, Field(gt=0, title='Min Experiments Before Outlier Check')
    ] = 1
